export type FindingCodeCitationKind =
  (typeof FindingCodeCitationKind)[keyof typeof FindingCodeCitationKind];

export const FindingCodeCitationKind = {
  "code-section": "code-section",
} as const;

/**
 * Inline citation referencing a code-section atom.
 */
export interface FindingCodeCitation {
  kind: FindingCodeCitationKind;
  /** The atom id used in `[[CODE:<atomId>]]` tokens. Must
resolve against the engine's reference block at
generation time; unresolved tokens are stripped from
`text` and reflected on the run row's
`invalidCitationCount`.
 */
  atomId: string;
}

export type FindingSourceCitationKind =
  (typeof FindingSourceCitationKind)[keyof typeof FindingSourceCitationKind];

export const FindingSourceCitationKind = {
  "briefing-source": "briefing-source",
} as const;

/**
 * Inline citation referencing a briefing-source row.
 */
export interface FindingSourceCitation {
  kind: FindingSourceCitationKind;
  id: string;
  /** Human-readable label used inside the inline token
`{{atom|briefing-source|<id>|<label>}}`. Echoed on the
citation pill the FE renders.
 */
  label: string;
}

export type FindingCitation = FindingCodeCitation | FindingSourceCitation;

/**
 * Pointer at the single backing briefing source for a finding.
Distinct from the `citations` array (which can carry many).

 */
export interface FindingSourceRef {
  id: string;
  label: string;
}

/**
 * One AIR-1 compliance finding. Wire shape mirrors
`findingsMock.ts:82-103` so the V1-6 frontend swap is a
single-file change. The `id` field is the public atom id
(`finding:{submissionId}:{rowUuid}`) — see
lib/db/src/schema/findings.ts column docs for the row pk vs
atom id split.

 */
export interface Finding {
  /** Public atom id. Carries the prefix grammar
`finding:{submissionId}:{ulid}` so URL deep-links can
derive the parent submission without a server round-trip.
 */
  id: string;
  submissionId: string;
  severity: FindingSeverity;
  category: FindingCategory;
  status: FindingStatus;
  /** Free-text body containing inline citation tokens. The
engine's validator has already stripped any token whose
id failed to resolve.
 */
  text: string;
  citations: FindingCitation[];
  /**
   * @minimum 0
   * @maximum 1
   */
  confidence: number;
  /** True iff the engine deemed this below the 0.6 threshold. */
  lowConfidence: boolean;
  reviewerStatusBy: FindingActor | null;
  reviewerStatusChangedAt: string | null;
  reviewerComment: string | null;
  /** Opaque BIM-element pointer the FE drill-in resolves to
a viewport selection (e.g. `wall:north-side-l2`).
 */
  elementRef: string | null;
  sourceRef: FindingSourceRef | null;
  /** When the engine produced the finding. Stamped at engine
time, not at row insert.
 */
  aiGeneratedAt: string;
  /** On override revisions, the original AI finding's atom id.
Null on AI-produced and never-overridden rows.
 */
  revisionOf: string | null;
}

/**
 * Single-finding wire envelope returned by accept / reject /
override.

 */
export interface FindingResponse {
  finding: Finding;
}

/**
 * Wire envelope for `GET /submissions/{id}/findings`. Includes
every row scoped to the submission — AI-produced, reviewer-
actioned, and override revisions alike. Sorting is the FE's
responsibility (severity then aiGeneratedAt; helper
`compareFindings` in findingsMock.ts:533-538).

 */
export interface ListSubmissionFindingsResponse {
  findings: Finding[];
}

/**
 * Optional body for `POST /submissions/{id}/findings/generate`.
Forward-looking — the V1-1 baseline ignores fields and always
runs a fresh full generation. Documented here so callers can
adopt the wire shape before regenerate semantics land.

 */
export interface GenerateSubmissionFindingsBody {
  /** When true, signals an explicit redo. Currently
informational — the route always runs a fresh generation.
 */
  regenerate?: boolean;
}

/**
 * Initial state — almost always `pending` on the 202.
 */
export type GenerateSubmissionFindingsResponseState =
  (typeof GenerateSubmissionFindingsResponseState)[keyof typeof GenerateSubmissionFindingsResponseState];

export const GenerateSubmissionFindingsResponseState = {
  pending: "pending",
  completed: "completed",
  failed: "failed",
} as const;

/**
 * 202 envelope returned by `POST /submissions/{id}/findings/generate`.
The job is identified by `generationId`; clients should poll
`/findings/status` until `state` reaches a terminal value,
then refetch `GET /findings` to read the persisted list.

 */
export interface GenerateSubmissionFindingsResponse {
  /** Opaque id for this generation job. */
  generationId: string;
  /** Initial state — almost always `pending` on the 202. */
  state: GenerateSubmissionFindingsResponseState;
}

export type SubmissionFindingsGenerationStatusResponseState =
  (typeof SubmissionFindingsGenerationStatusResponseState)[keyof typeof SubmissionFindingsGenerationStatusResponseState];

export const SubmissionFindingsGenerationStatusResponseState = {
  idle: "idle",
  pending: "pending",
  completed: "completed",
  failed: "failed",
} as const;

/**
 * Wire envelope for `GET /submissions/{id}/findings/status`.
State is persisted in `finding_runs`; the endpoint reads the
most recent row by `submission_id` ordered by `started_at`
DESC. Returns `idle` when no kickoff has ever run.

 */
export interface SubmissionFindingsGenerationStatusResponse {
  generationId: string | null;
  state: SubmissionFindingsGenerationStatusResponseState;
  startedAt: string | null;
  completedAt: string | null;
  error: string | null;
  invalidCitationCount: number | null;
  invalidCitations: string[] | null;
  /** Number of findings the engine produced that the discard
rule (no surviving citations + no elementRef OR text too
short) dropped entirely. Distinct dimension from
`invalidCitationCount` — see findingRuns.ts column docs.
Null while pending.
 */
  discardedFindingCount: number | null;
}

export type SubmissionFindingsGenerationRunState =
  (typeof SubmissionFindingsGenerationRunState)[keyof typeof SubmissionFindingsGenerationRunState];

export const SubmissionFindingsGenerationRunState = {
  pending: "pending",
  completed: "completed",
  failed: "failed",
} as const;

/**
 * One historical finding-generation attempt for a submission.
Same shape as the status response minus the `idle` enum
entry (idle = absence of a row, represented by omission).

 */
export interface SubmissionFindingsGenerationRun {
  generationId: string;
  state: SubmissionFindingsGenerationRunState;
  startedAt: string;
  completedAt: string | null;
  error: string | null;
  invalidCitationCount: number | null;
  invalidCitations: string[] | null;
  discardedFindingCount: number | null;
}

/**
 * Wire envelope for `GET /submissions/{id}/findings/runs`.
`runs` is the most recent attempts (newest first), capped by
the sweep's per-submission keep value.

 */
export interface SubmissionFindingsGenerationRunsResponse {
  runs: SubmissionFindingsGenerationRun[];
}

/**
 * Body for `POST /findings/{id}/override`. Mirrors
`OverrideFindingPayload` at findingsMock.ts:409-415. Atomic:
the route stamps the original `overridden` and inserts the
new revision in one transaction.

 */
export interface OverrideFindingBody {
  /** Reviewer-authored finding body. */
  text: string;
  severity: FindingSeverity;
  category: FindingCategory;
  /** Optional explanation of why the AI's original was wrong. */
  reviewerComment: string;
}

/**
 * Closed enum of reviewer-request action kinds. One-to-one with
`ReviewerRequestTargetType` — each kind targets exactly one
atom type (`refresh-briefing-source` → `briefing-source`,
etc.), and the route layer enforces the pairing at validate
time.

 */
export type ReviewerRequestKind =
  (typeof ReviewerRequestKind)[keyof typeof ReviewerRequestKind];

export const ReviewerRequestKind = {
  "refresh-briefing-source": "refresh-briefing-source",
  "refresh-bim-model": "refresh-bim-model",
  "regenerate-briefing": "regenerate-briefing",
} as const;

/**
 * Closed enum of reviewer-request lifecycle states. `pending` is
the initial state at insert; `dismissed` is the architect-
explicit reject path (carries `dismissalReason`); `resolved` is
set by the implicit-resolve hook when the matching domain
action emits its event (carries `triggeredActionEventId`).

 */
export type ReviewerRequestStatus =
  (typeof ReviewerRequestStatus)[keyof typeof ReviewerRequestStatus];

export const ReviewerRequestStatus = {
  pending: "pending",
  dismissed: "dismissed",
  resolved: "resolved",
} as const;

/**
 * Closed enum of target atom types a reviewer-request may anchor
against. Mirrors `REVIEWER_REQUEST_TARGET_TYPES` in
`lib/db/src/schema/reviewerRequests.ts` — adding a new target
type requires updating both the DB-side tuple and this enum so
the route validator and the atom composition list stay in sync.

 */
export type ReviewerRequestTargetType =
  (typeof ReviewerRequestTargetType)[keyof typeof ReviewerRequestTargetType];

export const ReviewerRequestTargetType = {
  "briefing-source": "briefing-source",
  "bim-model": "bim-model",
  "parcel-briefing": "parcel-briefing",
} as const;

/**
 * One reviewer-request row. `dismissedBy` / `dismissedAt` /
`dismissalReason` are populated only when `status` is
`dismissed`; `resolvedAt` / `triggeredActionEventId` only when
`status` is `resolved`.

 */
export interface ReviewerRequest {
  id: string;
  engagementId: string;
  requestKind: ReviewerRequestKind;
  targetEntityType: ReviewerRequestTargetType;
  targetEntityId: string;
  reason: string;
  status: ReviewerRequestStatus;
  requestedBy: FindingActor;
  requestedAt: string;
  dismissedBy: FindingActor | null;
  dismissedAt: string | null;
  dismissalReason: string | null;
  resolvedAt: string | null;
  triggeredActionEventId: string | null;
  createdAt: string;
  updatedAt: string;
}

/**
 * Request body for `POST /engagements/{id}/reviewer-requests`.
The `(requestKind, targetEntityType)` pair must satisfy the
kind-to-target-type contract defined in
`REVIEWER_REQUEST_KIND_TO_TARGET_TYPE` — the route validator
rejects mismatched pairings with 400.

 */
export interface CreateReviewerRequestBody {
  requestKind: ReviewerRequestKind;
  targetEntityType: ReviewerRequestTargetType;
  /**
   * @minLength 1
   * @maxLength 512
   */
  targetEntityId: string;
  /**
   * @minLength 1
   * @maxLength 4096
   */
  reason: string;
}

/**
 * Request body for `POST /reviewer-requests/{id}/dismiss`. The
`dismissalReason` is required so the architect must commit to
a written rationale — empty / whitespace bodies are rejected
with 400.

 */
export interface DismissReviewerRequestBody {
  /**
   * @minLength 1
   * @maxLength 4096
   */
  dismissalReason: string;
}

/**
 * Wire envelope for `POST /engagements/{id}/reviewer-requests`
and `POST /reviewer-requests/{id}/dismiss`. Carries the
affected row in the same shape the list endpoint returns so
the FE can splice the response into cached lists without a
follow-up fetch.

 */
export interface ReviewerRequestResponse {
  request: ReviewerRequest;
}

/**
 * Wire envelope for `GET /engagements/{id}/reviewer-requests`.
Newest-first list, optionally filtered by lifecycle state.

 */
export interface ListReviewerRequestsResponse {
  requests: ReviewerRequest[];
}

/**
 * Engagement metadata joined onto each row of the cross-engagement
"my outstanding requests" list (Reviewer V1-F / R13). Just the
three fields the FE renders inline on each row — `id` for the
deep-link target, `name` as the row's primary line,
`jurisdiction` as the secondary chip. The full engagement
envelope is not included; consumers that need it should follow
the link to `/engagements/{id}`.

 */
export interface ReviewerRequestEngagementSummary {
  id: string;
  name: string;
  jurisdiction: string | null;
}

/**
 * Reviewer-request row plus a small engagement-context envelope.
Returned only by the cross-engagement reviewer-side list at
`GET /reviewer-requests`; the per-engagement architect-side
list returns the bare `ReviewerRequest` shape because the
engagement is implicit from the path.

 */
export type ReviewerRequestWithEngagement = ReviewerRequest & {
  engagement: ReviewerRequestEngagementSummary;
};

/**
 * Wire envelope for `GET /reviewer-requests`. Newest-first list of
the calling reviewer's own reviewer-requests across every
engagement, with engagement metadata joined onto each row so
the FE can render without a follow-up fetch.

 */
export interface ListMyReviewerRequestsResponse {
  requests: ReviewerRequestWithEngagement[];
}

/**
 * XYZ vector in world coordinates. Y-up, Z+ = north convention
matches the FE BimViewer's three.js setup.

 */
export interface Vec3 {
  x: number;
  y: number;
  z: number;
}

/**
 * API-server domain render taxonomy. Distinct from mnml-client's
wire kind (`archdiffusion | video`) because `elevation-set` is
a fan-out concept that lives in the route, not on the wire
(Spec 54 v2 §6.2).

 */
export type DomainRenderKind =
  (typeof DomainRenderKind)[keyof typeof DomainRenderKind];

export const DomainRenderKind = {
  still: "still",
  "elevation-set": "elevation-set",
  video: "video",
} as const;

/**
 * Render lifecycle. Codebase-internal vocabulary; mnml's wire
statuses (`starting | processing | success | failed |
canceled`) translate to this set inside HttpMnmlClient.

 */
export type RenderStatus = (typeof RenderStatus)[keyof typeof RenderStatus];

export const RenderStatus = {
  queued: "queued",
  rendering: "rendering",
  ready: "ready",
  failed: "failed",
  cancelled: "cancelled",
} as const;

/**
 * Persistence-layer role taxonomy. The route's elevation-set
fan-out tags each output by which `camera_direction`
produced it; the video-thumbnail role is server-synthesized
via ffmpeg post-`ready` (mnml does not return a thumbnail).

 */
export type RenderOutputRole =
  (typeof RenderOutputRole)[keyof typeof RenderOutputRole];

export const RenderOutputRole = {
  primary: "primary",
  "elevation-n": "elevation-n",
  "elevation-e": "elevation-e",
  "elevation-s": "elevation-s",
  "elevation-w": "elevation-w",
  "video-primary": "video-primary",
  "video-thumbnail": "video-thumbnail",
} as const;

export type RenderCostBreakdownEntryKind =
  (typeof RenderCostBreakdownEntryKind)[keyof typeof RenderCostBreakdownEntryKind];

export const RenderCostBreakdownEntryKind = {
  archdiffusion: "archdiffusion",
  video: "video",
} as const;

/**
 * One bucket of the cost breakdown. An elevation-set's
breakdown has one entry with `count: 4` (four archdiffusion
calls); a still's has `count: 1`. Future kinds (e.g. a
compare-set of one archdiffusion + one video) would surface
as multiple entries.

 */
export interface RenderCostBreakdownEntry {
  kind: RenderCostBreakdownEntryKind;
  /** @minimum 1 */
  count: number;
  /** @minimum 0 */
  creditsPerCall: number;
  /** @minimum 0 */
  subtotal: number;
}

/**
 * Static cost estimate from `estimateRenderCost` in
`@workspace/mnml-client`. Spec 54 v2 §4 names the per-
operation credit costs as a static table — no quote call
to mnml. The kickoff response surfaces this so the FE can
render a "Render: N credits" chip without a second round-trip.

 */
export interface RenderCostEstimate {
  /** @minimum 0 */
  credits: number;
  breakdown: RenderCostBreakdownEntry[];
}

/**
 * mnml expert routing per Spec 54 v2 §2.1.
 */
export type KickoffRenderCommonFieldsExpertName =
  (typeof KickoffRenderCommonFieldsExpertName)[keyof typeof KickoffRenderCommonFieldsExpertName];

export const KickoffRenderCommonFieldsExpertName = {
  exterior: "exterior",
  interior: "interior",
  masterplan: "masterplan",
  landscape: "landscape",
  plan: "plan",
  product: "product",
} as const;

export type KickoffRenderCommonFieldsRenderStyle =
  (typeof KickoffRenderCommonFieldsRenderStyle)[keyof typeof KickoffRenderCommonFieldsRenderStyle];

export const KickoffRenderCommonFieldsRenderStyle = {
  raw: "raw",
  photoreal: "photoreal",
  cgi_render: "cgi_render",
  cad: "cad",
  freehand_sketch: "freehand_sketch",
  clay_model: "clay_model",
  illustration: "illustration",
  watercolor: "watercolor",
} as const;

/**
 * Per-expert flat string-map. The api-server passes each
entry through verbatim as a multipart field; mnml
validates against per-expert allowed values.

 */
export type KickoffRenderCommonFieldsExpertParams = { [key: string]: string };

/**
 * Common kickoff fields shared across every render kind.
 */
export interface KickoffRenderCommonFields {
  /** Absolute URL the headless capture browser fetches the GLB
from. The FE provides this — typically a signed object-
storage URL the FE already loaded into its viewer.
Server-side resolution from the bim-model row is V1-5.
 */
  glbUrl: string;
  /**
   * Free-form prompt forwarded to mnml as the
`archDiffusion-v43.prompt` (or `video-ai.prompt`) form
field. Spec 54 v2 §2.1 caps at 2000 chars.

   * @minLength 1
   * @maxLength 2000
   */
  prompt: string;
  /** mnml expert routing per Spec 54 v2 §2.1. */
  expertName?: KickoffRenderCommonFieldsExpertName;
  renderStyle?: KickoffRenderCommonFieldsRenderStyle;
  /** Per-expert flat string-map. The api-server passes each
entry through verbatim as a multipart field; mnml
validates against per-expert allowed values.
 */
  expertParams?: KickoffRenderCommonFieldsExpertParams;
}

export type KickoffRenderStillBodyKind =
  (typeof KickoffRenderStillBodyKind)[keyof typeof KickoffRenderStillBodyKind];

export const KickoffRenderStillBodyKind = {
  still: "still",
} as const;

export type KickoffRenderStillBody = KickoffRenderCommonFields & {
  kind: "still";
  cameraPosition: Vec3;
  cameraTarget: Vec3;
  /**
   * Field of view in degrees. Default 50 if omitted.
   * @minimum 10
   * @maximum 120
   */
  fov?: number;
} & {
  kind: KickoffRenderStillBodyKind;
};

export type KickoffRenderElevationSetBodyKind =
  (typeof KickoffRenderElevationSetBodyKind)[keyof typeof KickoffRenderElevationSetBodyKind];

export const KickoffRenderElevationSetBodyKind = {
  "elevation-set": "elevation-set",
} as const;

export type KickoffRenderElevationSetBody = KickoffRenderCommonFields & {
  kind: "elevation-set";
  buildingCenter: Vec3;
  /**
   * Meters from buildingCenter along each cardinal axis.

   * @exclusiveMinimum 0
   */
  cameraDistance: number;
  /** Meters above ground for the camera origin. */
  cameraHeight: number;
  /**
   * @minimum 10
   * @maximum 120
   */
  fov?: number;
} & {
  kind: KickoffRenderElevationSetBodyKind;
};

export type KickoffRenderVideoBodyKind =
  (typeof KickoffRenderVideoBodyKind)[keyof typeof KickoffRenderVideoBodyKind];

export const KickoffRenderVideoBodyKind = {
  video: "video",
} as const;

export type KickoffRenderVideoBody = KickoffRenderCommonFields & {
  kind: "video";
  cameraPosition: Vec3;
  cameraTarget: Vec3;
  duration: 5 | 10;
  /**
   * @minimum 0
   * @maximum 1
   */
  cfgScale?: number;
  aspectRatio?: "16:9" | "4:3" | "1:1";
  movementType?: "horizontal" | "vertical" | "zoom_in" | "zoom_out" | "pan";
  direction?: "left" | "right" | "up" | "down";
} & {
  kind: KickoffRenderVideoBodyKind;
};

export type KickoffRenderBody =
  | KickoffRenderStillBody
  | KickoffRenderElevationSetBody
  | KickoffRenderVideoBody;

/**
 * 202 envelope. The polling worker is fire-and-forget; clients
observe state via `GET /renders/{renderId}`.

 */
export interface KickoffRenderResponse {
  /** Opaque render id (the `viewpoint_renders.id` PK). */
  renderId: string;
  state: RenderStatus;
  kind: DomainRenderKind;
  cost: RenderCostEstimate;
}

export type RenderOutputProjectionFormat =
  (typeof RenderOutputProjectionFormat)[keyof typeof RenderOutputProjectionFormat];

export const RenderOutputProjectionFormat = {
  png: "png",
  jpg: "jpg",
  mp4: "mp4",
  webm: "webm",
} as const;

/**
 * Subset of `render_outputs` columns the FE / chat needs to
render the gallery row without a second round-trip. The full
Layer 3 surface lives on the `render-output` atom's typed
payload via `GET /atoms/render-output/{id}/summary`.

 */
export interface RenderOutputProjection {
  id: string;
  role: RenderOutputRole;
  format: RenderOutputProjectionFormat;
  resolution: string | null;
  sizeBytes: number | null;
  durationSeconds: number | null;
  /** GCS key under our durable bucket. NULL during the brief
unmirrored window between row insert and mirror
completion (the route writes both `source_url` and
`mirroredObjectKey` in the same transaction so a NULL
here on a `ready` parent is an error condition the sweep
surfaces).
 */
  mirroredObjectKey: string | null;
  thumbnailUrl: string | null;
  /** Relative path the FE hits to stream the durable mirrored
asset back (`/api/render-outputs/{id}/file`). NULL while
the row is still un-mirrored. Use this rather than
`thumbnailUrl`, which is null on still and elevation
outputs.
 */
  previewUrl: string | null;
  /** Same endpoint as `previewUrl` with `?download=1` so the
browser saves rather than navigates. NULL when
`mirroredObjectKey` is NULL.
 */
  downloadUrl: string | null;
  seed: number | null;
}

